mapper.select:
SELECT rp.id_ as id, rp.deployment_id_ as deploymentId, rd.name_ as name, rd.category_ as category, rp.key_ as flowKey, rp.version_ as version, rp.suspension_state_ as suspensionState, rd.deploy_time_ as deploymentTime FROM ACT_RE_PROCDEF rp LEFT JOIN ACT_RE_DEPLOYMENT rd ON rp.deployment_id_ = rd.id_
and rp.KEY_ = #{key}
order by rd.deploy_time_ desc
